SELECT 'MV-' || TO_CHAR(SYSDATE,'YYYYMMDD-') || LPAD(SEQ_MOVIE_PK.NEXTVAL, 6,'0')
  FROM DUAL

INSERT INTO TMDB.MOVIE
     ( MOVIE_ID
     , POSTER_URL
     , TITLE
     , MOVIE_RATING
     , OPEN_DATE
     , OPEN_COUNTRY
     , RUNNING_TIME
     , INTRODUCE
     , SYNOPSIS
     , ORIGINAL_TITLE
     , STATE
     , LANGUAGE
     , BUDGET
     , PROFIT)            
VALUES
      (#{movieId}
     , 'null'
     , #{title}
     , #{movieRating}
     , #{openDate}
     , #{openCountry}
     , #{runningTime}
     , #{introduce}
     , #{synopsis}
     , #{originalTitle}
     , #{state}
     , #{language}
     , #{budget}
     , #{profit})

